-- Register anonymous target candidate builder output fields and shared values.
-- These names are emitted by the Layer 3 candidate-preparation scaffold and are
-- consumed as point-in-time TargetStateVectorModel preprocessing evidence.

ON CONFLICT (id) DO UPDATE SET
    kind = EXCLUDED.kind,
    key = EXCLUDED.key,
    payload_format = EXCLUDED.payload_format,
    payload = EXCLUDED.payload,
    path = EXCLUDED.path,
    applies_to = EXCLUDED.applies_to,
    artifact_sync_policy = EXCLUDED.artifact_sync_policy,
    note = EXCLUDED.note,
    updated_at = CURRENT_TIMESTAMP;
